if(!defined("IN_ESOTALK"))exit;class join extends Controller{var $view="join.view.php";var $reservedNames=array("guest","member","members","moderator","moderators","administrator","administrators","admin","suspended","esotalk","name","password","everyone","myself");function init(){if($this->esoTalk->user)redirect("settings");global $language,$config;$this->title=$language["Join this forum"];if(isset($_GET["q2"])){if($_GET["q2"]=="sendVerification"){$memberId=(int)@$_GET["q3"];if(list($email,$name,$password)=$this->esoTalk->db->fetchRow("SELECT email, name, password FROM {$config["tablePrefix"]}members WHERE memberId=$memberId AND account='Unvalidated'"))$this->sendVerificationEmail($email,$name,$memberId.$password);$this->esoTalk->message("verifyEmail",false);redirect("");}else $this->validateMember($_GET["q2"]);return;}$this->form=array("accountInformation"=>array("legend"=>$language["Account information"],100=>array("id"=>"name","html"=>@"<label>{$language["Username"]}</label> <input id='name' name='join[name]' type='text' class='text' autocomplete='username' value='{$_POST["join"]["name"]}' maxlength='16' tabindex='100'/>","validate"=>array($this,"validateName"),"required"=>true,"databaseField"=>"name","ajax"=>true),200=>array("id"=>"email","html"=>@"<label>{$language["Email"]}</label> <input id='email' name='join[email]' type='text' class='text' autocomplete='email' value='{$_POST["join"]["email"]}' maxlength='63' tabindex='200'/>","validate"=>"validateEmail","required"=>true,"databaseField"=>"email","message"=>"emailInfo","ajax"=>true),300=>array("id"=>"password","html"=>@"<label>{$language["Password"]}</label> <input id='password' name='join[password]' type='password' class='text' autocomplete='new-password' value='{$_POST["join"]["password"]}' tabindex='300'/>","validate"=>"validatePassword","required"=>true,"databaseField"=>"password","message"=>"passwordInfo","ajax"=>true),400=>array("id"=>"confirm","html"=>@"<label>{$language["Confirm password"]}</label> <input id='confirm' name='join[confirm]' type='password' class='text' autocomplete='new-password' value='{$_POST["join"]["confirm"]}' tabindex='400'/>","required"=>true,"validate"=>array($this,"validateConfirmPassword"),"ajax"=>true)));$this->callHook("init");$this->fields=array();foreach($this->form as $k=>$fieldset){if(!is_array($fieldset))continue;foreach($fieldset as $j=>$field){if(!is_array($field))continue;$this->fields[$field["id"]]=&$this->form[$k][$j];}}if(isset($_POST["join"]) and $this->addMember()){$this->esoTalk->message("verifyEmail",false);redirect("");}}function ajax(){if($return=$this->callHook("ajax",null,true))return $return;switch($_POST["action"]){case "validate":if($msg=@call_user_func_array($this->fields[$_POST["field"]]["validate"],array(&$_POST["value"])))return array("validated"=>false,"message"=>$this->esoTalk->htmlMessage($msg));else return array("validated"=>true,"message"=>"");}}function addMember(){global $config;$validationError=false;foreach($this->fields as $k=>$field){if(!is_array($field))continue;$this->fields[$k]["input"]=@$_POST["join"][$field["id"]];if((!empty($field["required"]) or $this->fields[$k]["input"]) and !empty($field["validate"]) and ($msg=@call_user_func_array($field["validate"],array(&$this->fields[$k]["input"])))){$validationError=true;$this->fields[$k]["message"]=$msg;$this->fields[$k]["error"]=true;}else $this->fields[$k]["success"]=true;}$this->callHook("validateForm",array(&$validationError));if($validationError)return false;$insertData=array();foreach($this->fields as $field){if(!is_array($field))continue;if(!empty($field["databaseField"]))$insertData[$field["databaseField"]]=!empty($field["checkbox"])?($field["input"]?1:0):"'{$field["input"]}'";}$insertData["color"]="FLOOR(1 + (RAND() * {$this->esoTalk->skin->numberOfColors}))";$insertData["language"]="'".$this->esoTalk->db->escape($config["language"])."'";$insertData["avatarAlignment"]="'{$_SESSION["avatarAlignment"]}'";$this->callHook("beforeAddMember",array(&$insertData));$insertQuery=$this->esoTalk->db->constructInsertQuery("members",$insertData);$insertQuery="REPLACE".substr($insertQuery,6);$this->esoTalk->db->query($insertQuery);$memberId=$this->esoTalk->db->lastInsertId();$this->callHook("afterAddMember",array($memberId));$this->sendVerificationEmail($_POST["join"]["email"],$_POST["join"]["name"],$memberId.md5($config["salt"].$_POST["join"]["password"]));return true;}function sendVerificationEmail($email,$name,$verifyHash){global $language,$config;sendEmail($email,sprintf($language["emails"]["join"]["subject"],$name),sprintf($language["emails"]["join"]["body"],$name,$config["forumTitle"],$config["baseURL"].makeLink("join",$verifyHash)));}function validateMember($hash){global $config;$memberId=(int)substr($hash,0,strlen($hash)-32);$password=$this->esoTalk->db->escape(substr($hash,-32));if($name=@$this->esoTalk->db->result($this->esoTalk->db->query("SELECT name FROM {$config["tablePrefix"]}members WHERE memberId=$memberId AND password='$password' AND account='Unvalidated'"),0)){$this->esoTalk->db->query("UPDATE {$config["tablePrefix"]}members SET account='Member' WHERE memberId=$memberId");$this->esoTalk->login($name,false,$password);$this->esoTalk->message("accountValidated",false);}redirect("");}function addToForm($fieldset,$field,$position=false){return addToArray($this->form[$fieldset],$field,$position);}function addFieldset($fieldset,$legend,$position=false){return addToArrayString($this->form,$fieldset,array("legend"=>$legend),$position);}function validateConfirmPassword($password){if($password!=(defined("AJAX_REQUEST")?$_POST["password"]:$_POST["join"]["password"]))return "passwordsDontMatch";}function validateName(&$name){global $config;$name=substr($name,0,31);if(in_array(strtolower($name),$this->reservedNames))return "nameTaken";if(!strlen($name))return "nameEmpty";if(preg_match("/[".preg_quote("!/%+-","/")."]/",$name))return "invalidCharacters";if(@$this->esoTalk->db->result($this->esoTalk->db->query("SE